async function main() {
  let updated = 0;
  let totalWords = 0;
  let minWords = Infinity;
  let maxWords = 0;
  let totalMetaLen = 0;

  for (const item of updates) {
    try {
      const result = await prisma.product.update({
        where: { id: item.id },
        data: { description: item.description, metaDescription: item.metaDescription }
      });
      const wordCount = item.description.split(/\s+/).length;
      const metaLen = item.metaDescription.length;
      totalWords += wordCount;
      totalMetaLen += metaLen;
      if (wordCount < minWords) minWords = wordCount;
      if (wordCount > maxWords) maxWords = wordCount;
      updated++;
      console.log(`✅ [${updated}] Updated: ${result.slug} (${wordCount} words, meta ${metaLen} chars)`);
    } catch (error) {
      console.error(`❌ Error updating ${item.id}: ${error.message}`);
    }
  }

  console.log(`\n${"=".repeat(60)}`);
  console.log(`✅ Batch R6G-R6J complete`);
  console.log(`   Products updated: ${updated}`);
  console.log(`   Avg description word count: ${(totalWords / updated).toFixed(0)}`);
  console.log(`   Min word count: ${minWords}`);
  console.log(`   Max word count: ${maxWords}`);
  console.log(`   Avg meta description length: ${(totalMetaLen / updated).toFixed(0)} chars`);
  console.log(`${"=".repeat(60)}`);
}

main().then(() => prisma.$disconnect());
